sql:
SELECT streamer_id, maturity_rating, rating_date
FROM maturity_ratings
WHERE maturity_rating = 'Teen';

SELECT SUM(followers_gained) AS total_followers_gained
FROM follower_gains
WHERE streamer_id = 1;

SELECT SUM(views_gained) AS total_views_gained
FROM view_gains
WHERE streamer_id = 1 AND gain_date BETWEEN '2023-01-01' AND '2023-01-31';

SELECT view_count
FROM streams
WHERE stream_id = 1;

SELECT SUM(followers_gained) AS total_followers_gained
FROM follower_gains
WHERE streamer_id = 0 AND gain_date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT streamer_id, SUM(views_gained) AS total_views_gained
FROM view_gains
GROUP BY streamer_id;

external_knowledge:
- 'Crossed the 30-minute mark' refers to an average stream duration of more than 1800 seconds (or 30 minutes); 
- 'Twitch Partner' is a program that offers streamers additional features and support, indicating 's.is_partner = 1';
- 'Gained followers in January 2023' refers to 'fg.gain_date BETWEEN '2023-01-01' AND '2023-01-31'.

